1	export type Item = Record<string, unknown>;
2	export type QuoteStep = { op: "quote"; items: Item[] };
3	export type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Array<{ itemType: string; amount: number }> } };
4	export type Step = QuoteStep | ClaimStep;
5	export type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
6	export type QuoteResult = { premium: number };
7	export type ClaimResult = { payout: number; remainingCap: number };
8	export type ScenarioResult = { results: Array<QuoteResult | ClaimResult> };
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
12	
13	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const itemBasePremium = (item: Item): number =>
23	  BASE_PREMIUM_BY_TYPE[item.type as string] ?? 0;
24	
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	const COMPONENT_BLOCK_SIZE = 3;
27	const COMPONENT_BLOCK_BASE = 60;
28	
29	const countByType = (items: Item[]): Map<string, number> => {
30	  const counts = new Map<string, number>();
31	  for (const item of items) {
32	    const type = item.type as string;
33	    counts.set(type, (counts.get(type) ?? 0) + 1);
34	  }
35	  return counts;
36	};
37	
38	const typeGroupBase = (type: string, count: number): number => {
39	  const unitBase = BASE_PREMIUM_BY_TYPE[type] ?? 0;
40	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
41	    return COMPONENT_BLOCK_BASE;
42	  }
43	  return count * unitBase;
44	};
45	
46	const itemsBaseSum = (items: Item[]): number => {
47	  let total = 0;
48	  for (const [type, count] of countByType(items)) {
49	    total += typeGroupBase(type, count);
50	  }
51	  return total;
52	};
53	
54	const CURSE_SURCHARGE_RATE = 0.5;
55	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
56	const HIGH_ENCHANTMENT_THRESHOLD = 5;
57	
58	const itemCurseSurcharge = (item: Item): number =>
59	  item.cursed === true ? itemBasePremium(item) * CURSE_SURCHARGE_RATE : 0;
60	
61	const itemHighEnchantmentSurcharge = (item: Item): number => {
62	  const ench = item.enchantment;
63	  return typeof ench === "number" && ench >= HIGH_ENCHANTMENT_THRESHOLD
64	    ? itemBasePremium(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
65	    : 0;
66	};
67	
68	const itemSpecificSurchargesSum = (items: Item[]): number =>
69	  items.reduce(
70	    (sum, item) =>
71	      sum + itemCurseSurcharge(item) + itemHighEnchantmentSurcharge(item),
72	    0,
73	  );
74	
75	const LOYALTY_DISCOUNT_RATE = 0.2;
76	const LOYALTY_YEARS_THRESHOLD = 2;
77	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
78	
79	const loyaltyDiscount = (baseSum: number, yearsWithMHPCO: number): number =>
80	  yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? baseSum * LOYALTY_DISCOUNT_RATE : 0;
81	
82	const followUpDiscount = (baseSum: number, priorQuoteCount: number): number =>
83	  priorQuoteCount > 0 ? baseSum * FOLLOW_UP_DISCOUNT_RATE : 0;
84	
85	const quotePremium = (
86	  items: Item[],
87	  customer: { yearsWithMHPCO: number },
88	  priorQuoteCount: number,
89	): number => {
90	  const baseSum = itemsBaseSum(items);
91	  const firstInsuranceSurcharge = baseSum * FIRST_INSURANCE_SURCHARGE_RATE;
92	  const itemSurcharges = itemSpecificSurchargesSum(items);
93	  const loyalty = loyaltyDiscount(baseSum, customer.yearsWithMHPCO);
94	  const followUp = followUpDiscount(baseSum, priorQuoteCount);
95	  return Math.ceil(
96	    baseSum + itemSurcharges - loyalty - followUp + firstInsuranceSurcharge + PROCESSING_FEE,
97	  );
98	};
99	
100	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
101	  sword: 1000,
102	  amulet: 600,
103	  staff: 800,
104	  potion: 400,
105	  rune: 250,
106	  moonstone: 250,
107	};
108	
109	const DEDUCTIBLE_PER_DAMAGE = 100;
110	const CAP_MULTIPLIER = 2;
111	
112	const itemInsuranceValue = (item: Item): number =>
113	  INSURANCE_VALUE_BY_TYPE[item.type as string] ?? 0;
114	
115	const insuranceSum = (items: Item[]): number =>
116	  items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
117	
118	type Policy = { items: Item[]; remainingCap: number };
119	
120	type ScenarioState = { priorQuoteCount: number; policies: Policy[] };
121	
122	const initialState = (): ScenarioState => ({ priorQuoteCount: 0, policies: [] });
123	
124	const damagePayout = (damage: { itemType: string; amount: number }): number =>
125	  Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE);
126	
127	const handleQuoteStep = (
128	  step: QuoteStep,
129	  customer: Scenario["customer"],
130	  state: ScenarioState,
131	): { result: QuoteResult; state: ScenarioState } => {
132	  const policy: Policy = {
133	    items: step.items,
134	    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
135	  };
136	  return {
137	    result: { premium: quotePremium(step.items, customer, state.priorQuoteCount) },
138	    state: {
139	      priorQuoteCount: state.priorQuoteCount + 1,
140	      policies: [...state.policies, policy],
141	    },
142	  };
143	};
144	
145	const handleClaimStep = (
146	  step: ClaimStep,
147	  state: ScenarioState,
148	): { result: ClaimResult; state: ScenarioState } => {
149	  const policy = state.policies[step.policy];
150	  const rawPayout = step.incident.damages.reduce(
151	    (sum, damage) => sum + damagePayout(damage),
152	    0,
153	  );
154	  const payout = Math.floor(Math.min(rawPayout, policy.remainingCap));
155	  const remainingCap = policy.remainingCap - payout;
156	  const updatedPolicies = state.policies.map((p, i) =>
157	    i === step.policy ? { ...p, remainingCap } : p,
158	  );
159	  return {
160	    result: { payout, remainingCap },
161	    state: { ...state, policies: updatedPolicies },
162	  };
163	};
164	
165	const handleStep = (
166	  step: Step,
167	  customer: Scenario["customer"],
168	  state: ScenarioState,
169	): { result: QuoteResult | ClaimResult; state: ScenarioState } =>
170	  step.op === "quote"
171	    ? handleQuoteStep(step, customer, state)
172	    : handleClaimStep(step, state);
173	
174	export const runScenario = (scenario: Scenario): ScenarioResult => {
175	  const results: Array<QuoteResult | ClaimResult> = [];
176	  let state = initialState();
177	  for (const step of scenario.steps) {
178	    const next = handleStep(step, scenario.customer, state);
179	    results.push(next.result);
180	    state = next.state;
181	  }
182	  return { results };
183	};
